import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;

public class SolutionTest {

    @Test
    void appendThenUndoLast() {
        // APPEND:hello, APPEND: world, UNDO -> "hello"
        assertEquals("hello",
                new Solution().finalDocument(
                        new String[]{"APPEND:hello", "APPEND: world", "UNDO"}));
    }

    @Test
    void emptyOps() {
        assertEquals("",
                new Solution().finalDocument(new String[]{}));
    }

    @Test
    void undoOnEmptyDocumentIsNoOp() {
        // UNDO with nothing to undo returns empty string, no exception
        assertEquals("",
                new Solution().finalDocument(new String[]{"UNDO"}));
    }

    @Test
    void undoUnderfow() {
        // APPEND:a, UNDO (removes a), UNDO (no-op) -> ""
        assertEquals("",
                new Solution().finalDocument(
                        new String[]{"APPEND:a", "UNDO", "UNDO"}));
    }

    @Test
    void orderMatters() {
        // APPEND:X, UNDO, APPEND:Y -> "Y"
        // If order were ignored and both APPENDs applied: would be "XY"
        assertEquals("Y",
                new Solution().finalDocument(
                        new String[]{"APPEND:X", "UNDO", "APPEND:Y"}));
    }

    @Test
    void multipleAppendsNoUndo() {
        assertEquals("abc",
                new Solution().finalDocument(
                        new String[]{"APPEND:a", "APPEND:b", "APPEND:c"}));
    }

    @Test
    void undoThenAppendRebuildsDocument() {
        // APPEND:hello, APPEND: world, UNDO, APPEND:!, no undo -> "hello!"
        assertEquals("hello!",
                new Solution().finalDocument(
                        new String[]{"APPEND:hello", "APPEND: world", "UNDO", "APPEND:!"}));
    }
}
